import argparse
import sys
import os
import json
from kafka.admin import KafkaAdminClient, NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import KafkaError, TopicAlreadyExistsError, UnknownTopicOrPartitionError
import logging

logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)


def get_kafka_config():
    """Get Kafka configuration from environment variables for security"""
    bootstrap_servers = os.environ.get('KAFKA_BOOTSTRAP_SERVERS', 'localhost:9092')
    
    config = {
        'bootstrap_servers': bootstrap_servers.split(','),
        'client_id': 'kafka-admin-client'
    }
    
    # SASL authentication
    sasl_mechanism = os.environ.get('KAFKA_SASL_MECHANISM')
    if sasl_mechanism:
        config['security_protocol'] = os.environ.get('KAFKA_SECURITY_PROTOCOL', 'SASL_SSL')
        config['sasl_mechanism'] = sasl_mechanism
        config['sasl_plain_username'] = os.environ.get('KAFKA_SASL_USERNAME')
        config['sasl_plain_password'] = os.environ.get('KAFKA_SASL_PASSWORD')
    
    # SSL configuration
    ssl_cafile = os.environ.get('KAFKA_SSL_CAFILE')
    if ssl_cafile:
        config['ssl_cafile'] = ssl_cafile
        config['ssl_certfile'] = os.environ.get('KAFKA_SSL_CERTFILE')
        config['ssl_keyfile'] = os.environ.get('KAFKA_SSL_KEYFILE')
    
    return config


def create_admin_client():
    """Create and return Kafka admin client with secure configuration"""
    try:
        config = get_kafka_config()
        admin_client = KafkaAdminClient(**config)
        logger.info("Successfully connected to Kafka cluster")
        return admin_client
    except Exception as e:
        logger.error(f"Failed to create admin client: {e}")
        sys.exit(1)


def create_topics(admin_client, topics_config):
    """Create topics with specified configuration"""
    new_topics = []
    
    for topic_config in topics_config:
        topic_name = topic_config['name']
        num_partitions = topic_config.get('partitions', 1)
        replication_factor = topic_config.get('replication_factor', 1)
        topic_configs = topic_config.get('configs', {})
        
        new_topic = NewTopic(
            name=topic_name,
            num_partitions=num_partitions,
            replication_factor=replication_factor,
            topic_configs=topic_configs
        )
        new_topics.append(new_topic)
    
    try:
        result = admin_client.create_topics(new_topics=new_topics, validate_only=False)
        for topic, future in result.items():
            try:
                future.result()
                logger.info(f"Topic '{topic}' created successfully")
            except TopicAlreadyExistsError:
                logger.warning(f"Topic '{topic}' already exists")
            except Exception as e:
                logger.error(f"Failed to create topic '{topic}': {e}")
    except Exception as e:
        logger.error(f"Error creating topics: {e}")


def delete_topics(admin_client, topic_names):
    """Delete specified topics"""
    try:
        result = admin_client.delete_topics(topics=topic_names)
        for topic, future in result.items():
            try:
                future.result()
                logger.info(f"Topic '{topic}' deleted successfully")
            except UnknownTopicOrPartitionError:
                logger.warning(f"Topic '{topic}' does not exist")
            except Exception as e:
                logger.error(f"Failed to delete topic '{topic}': {e}")
    except Exception as e:
        logger.error(f"Error deleting topics: {e}")


def list_topics(admin_client):
    """List all topics in the cluster"""
    try:
        topics = admin_client.list_topics()
        logger.info("Topics in cluster:")
        for topic in topics:
            logger.info(f"  - {topic}")
        return topics
    except Exception as e:
        logger.error(f"Error listing topics: {e}")
        return []


def describe_topics(admin_client, topic_names):
    """Describe topic configurations"""
    try:
        metadata = admin_client._client.cluster
        metadata.request_update()
        
        for topic_name in topic_names:
            topic_metadata = metadata.topics().get(topic_name)
            if topic_metadata:
                logger.info(f"\nTopic: {topic_name}")
                logger.info(f"  Partitions: {len(topic_metadata.partitions)}")
                for partition_id, partition in topic_metadata.partitions.items():
                    logger.info(f"    Partition {partition_id}: Leader={partition.leader}, Replicas={partition.replicas}, ISR={partition.isr}")
            else:
                logger.warning(f"Topic '{topic_name}' not found")
    except Exception as e:
        logger.error(f"Error describing topics: {e}")


def alter_topic_config(admin_client, topic_name, configs):
    """Alter topic configuration"""
    try:
        config_resource = ConfigResource(ConfigResourceType.TOPIC, topic_name)
        
        for key, value in configs.items():
            config_resource.set_config(key, value)
        
        result = admin_client.alter_configs([config_resource])
        for resource, future in result.items():
            try:
                future.result()
                logger.info(f"Configuration for topic '{topic_name}' updated successfully")
            except Exception as e:
                logger.error(f"Failed to update configuration for topic '{topic_name}': {e}")
    except Exception as e:
        logger.error(f"Error altering topic configuration: {e}")


def describe_topic_config(admin_client, topic_names):
    """Describe topic configurations"""
    try:
        config_resources = [ConfigResource(ConfigResourceType.TOPIC, name) for name in topic_names]
        result = admin_client.describe_configs(config_resources)
        
        for resource, future in result.items():
            try:
                configs = future.result()
                logger.info(f"\nConfiguration for topic '{resource.name}':")
                for config_name, config_value in configs.items():
                    logger.info(f"  {config_name}: {config_value.value} (source: {config_value.source})")
            except Exception as e:
                logger.error(f"Failed to describe configuration for topic '{resource.name}': {e}")
    except Exception as e:
        logger.error(f"Error describing topic configurations: {e}")


def create_partitions(admin_client, topic_partitions):
    """Increase partition count for topics"""
    try:
        from kafka.admin import NewPartitions
        
        new_partitions = {}
        for topic_name, total_count in topic_partitions.items():
            new_partitions[topic_name] = NewPartitions(total_count=total_count)
        
        result = admin_client.create_partitions(new_partitions)
        for topic, future in result.items():
            try:
                future.result()
                logger.info(f"Partitions for topic '{topic}' updated successfully")
            except Exception as e:
                logger.error(f"Failed to update partitions for topic '{topic}': {e}")
    except Exception as e:
        logger.error(f"Error creating partitions: {e}")


def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration Tool')
    parser.add_argument('action', choices=['create', 'delete', 'list', 'describe', 'alter-config', 
                                          'describe-config', 'add-partitions'],
                       help='Action to perform')
    parser.add_argument('--topics', nargs='+', help='Topic names')
    parser.add_argument('--config-file', help='JSON file with topic configurations')
    parser.add_argument('--partitions', type=int, help='Number of partitions')
    parser.add_argument('--replication-factor', type=int, help='Replication factor')
    parser.add_argument('--topic-config', action='append', nargs=2, metavar=('KEY', 'VALUE'),
                       help='Topic configuration key-value pairs')
    parser.add_argument('--partition-count', type=int, help='New total partition count for add-partitions')
    
    args = parser.parse_args()
    
    admin_client = create_admin_client()
    
    try:
        if args.action == 'create':
            if args.config_file:
                with open(args.config_file, 'r') as f:
                    topics_config = json.load(f)
            else:
                if not args.topics:
                    logger.error("--topics required for create action")
                    sys.exit(1)
                
                topic_configs = {}
                if args.topic_config:
                    topic_configs = {k: v for k, v in args.topic_config}
                
                topics_config = [{
                    'name': topic,
                    'partitions': args.partitions or 1,
                    'replication_factor': args.replication_factor or 1,
                    'configs': topic_configs
                } for topic in args.topics]
            
            create_topics(admin_client, topics_config)
        
        elif args.action == 'delete':
            if not args.topics:
                logger.error("--topics required for delete action")
                sys.exit(1)
            delete_topics(admin_client, args.topics)
        
        elif args.action == 'list':
            list_topics(admin_client)
        
        elif args.action == 'describe':
            if not args.topics:
                logger.error("--topics required for describe action")
                sys.exit(1)
            describe_topics(admin_client, args.topics)
        
        elif args.action == 'alter-config':
            if not args.topics or len(args.topics) != 1:
                logger.error("Exactly one topic required for alter-config action")
                sys.exit(1)
            if not args.topic_config:
                logger.error("--topic-config required for alter-config action")
                sys.exit(1)
            
            configs = {k: v for k, v in args.topic_config}
            alter_topic_config(admin_client, args.topics[0], configs)
        
        elif args.action == 'describe-config':
            if not args.topics:
                logger.error("--topics required for describe-config action")
                sys.exit(1)
            describe_topic_config(admin_client, args.topics)
        
        elif args.action == 'add-partitions':
            if not args.topics or not args.partition_count:
                logger.error("--topics and --partition-count required for add-partitions action")
                sys.exit(1)
            
            topic_partitions = {topic: args.partition_count for topic in args.topics}
            create_partitions(admin_client, topic_partitions)
    
    finally:
        admin_client.close()


if __name__ == '__main__':
    main()